import { AfterViewInit, Component, ElementRef, OnDestroy, OnInit, ViewChild } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { MatPaginator } from '@angular/material/paginator';
import { MatTableDataSource } from '@angular/material/table';
import { forkJoin, fromEvent, Subscription } from 'rxjs';
import { debounceTime, finalize } from 'rxjs/operators';

import { IAccountData } from '../interface/account-entry';
import { EventService } from 'app/shared/services/event.service';
import { NotificationService } from 'app/shared/services/notification.service';
import { DatabaseService } from '../services/database.service';



@Component({
  selector: 'app-accounts',
  templateUrl: './accounts.component.html',
  styleUrls: ['./accounts.component.scss'],
  host: {
    'class': 'd-flex flex-column flex-nowrap w-100 h-100'
  }
})
export class AccountsComponent implements OnInit, AfterViewInit, OnDestroy {
  dataSource: MatTableDataSource<IAccountData>;
  secondaryDataSource: MatTableDataSource<IAccountData>;
  displayedColumns = ['name', 'groupName', 'balanceMoney', 'tailNo'];

  @ViewChild('flexFillContainer') private flexFillContainer: ElementRef<HTMLElement>;
  @ViewChild(MatPaginator) private paginator: MatPaginator;
  private pageSize = 20;
  private subscription = new Subscription();

  constructor(
    private router: Router,
    private route: ActivatedRoute,
    private elementRef: ElementRef<HTMLElement>,
    private eventService: EventService,
    private notification: NotificationService,
    private databaseService: DatabaseService
  ) {
    this.dataSource = new MatTableDataSource();
    this.secondaryDataSource = new MatTableDataSource();
  }

  ngOnInit(): void {
    this.subscription.add(
      this.eventService.onViewportDimensionChange().pipe(debounceTime(300)).subscribe((change) => {
        if (change.height) {
          this.adjustPageSize();
        }
      })
    );
  }

  ngAfterViewInit(): void {
    this.secondaryDataSource.paginator = this.paginator;
    setTimeout(() => {
      this.adjustPageSize();
    });

    this.notification.showLoading(this.elementRef.nativeElement);
    forkJoin([
      this.databaseService.getVisibleAccountList(),
      this.databaseService.getHiddenAccountList()
    ]).pipe(
      finalize(() => {
        this.notification.hideLoading();
      })
    ).subscribe((datas) => {
      const visibleAccountsData = datas[0];
      const hiddenAccountsData = datas[1];
      let visibleAccountList: Array<IAccountData> = [];

      visibleAccountsData.data.accountList.forEach((item) => {
        item.accountData.forEach((account) => {
          account.groupName = item.groupName;
          account.balanceMoney = account.balanceMoney / 100;
        });
        visibleAccountList.push({
          name: '',
          groupName: item.groupName,
          balanceMoney: item.groupMoney.summaryAssets / 100,
          moneyType: item.groupMoney.allMoneyCategory[0].moneyType
        } as IAccountData);
        visibleAccountList = visibleAccountList.concat(item.accountData);
      });
      this.dataSource.data = visibleAccountList;

      this.secondaryDataSource.data = hiddenAccountsData.data;
    });
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }

  goToEntryList(account: IAccountData): void  {
    this.router.navigate(['accounts', account.uuid], {
      relativeTo: this.route.parent
    });
  }

  private adjustPageSize(): void {
    const pageSize = Math.floor((this.flexFillContainer.nativeElement.offsetHeight - 56) / 48);

    this.pageSize = Math.max(10, pageSize);
    this.paginator._changePageSize(this.pageSize);
  }
}
