import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';

import { IBankListResponse, ICardListResponse } from '../interface/http-response-types';
import { RequestService } from './request.service';



@Injectable()
export class AdditionalDataService {

  constructor(private requestService: RequestService) { }

  getBankList(): Observable<IBankListResponse> {
    return this.requestService.get('setting/account_bankList.action', {
      type: ''
    }) as Observable<IBankListResponse>;
  }

  getCardTypeList(): Observable<ICardListResponse> {
    return this.requestService.get('setting/account_cardList.action', {
      type: ''
    }) as Observable<ICardListResponse>;
  }
}
