import {
  Component,
  ElementRef,
  OnDestroy,
  OnInit,
  ViewChild,
} from '@angular/core';
import { FormControl, FormGroup } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { SelectionModel } from '@angular/cdk/collections';
import { MatSelectChange } from '@angular/material/select';
import { MatPaginator, PageEvent } from '@angular/material/paginator';
import { MatTableDataSource } from '@angular/material/table';
import { forkJoin, merge, of, Subscription } from 'rxjs';
import {
  catchError,
  debounceTime,
  finalize,
  map,
  startWith,
  switchMap,
} from 'rxjs/operators';

import { ENTRY_TYPES } from '../types';
import { IBook, IBookMember, IBookProject } from '../interface/book';
import {
  IAccountDetailEntry,
  IBaseAccountData,
  IPayCategory,
  ITransactionObject,
} from '../interface/account-entry';
import { AlgorithmService } from 'app/shared/services/algorithm.service';
import { EventService } from 'app/shared/services/event.service';
import { CommunicationService } from 'app/shared/services/communication.service';
import { NotificationService } from 'app/shared/services/notification.service';
import { DatetimeService } from '../services/datetime.service';
import { DatabaseService } from '../services/database.service';

@Component({
  selector: 'app-search-entries',
  templateUrl: './search-entries.component.html',
  styleUrls: ['./search-entries.component.scss'],
  host: {
    class: 'd-flex flex-column flex-nowrap w-100 h-100',
  },
})
export class SearchEntriesComponent implements OnInit, OnDestroy {
  books: Array<IBook> = [];
  recordTypes = [
    ENTRY_TYPES.PAY,
    ENTRY_TYPES.REVENUE,
    ENTRY_TYPES.TRANSFER,
    ENTRY_TYPES.BORROW,
    ENTRY_TYPES.RETURN,
  ];
  accounts: Array<IBaseAccountData> = [];
  projects: Array<IBookProject> = [];
  members: Array<IBookMember> = [];
  payCategories: Array<IPayCategory> = [];
  txnObjects: Array<ITransactionObject> = [];

  searchKeys = {
    bkId: null,
    startTime: 0,
    endTime: 0,
    amountStart: null,
    amountEnd: null,
    comment: '',
    recTypeList: null,
    mainTypeIdList: null,
    subTypeIdList: null,
    accountIdList: null,
    projectIdList: null,
    tradetgtIdList: null,
    memberIdList: null,
    reimburseList: null,
    pageSize: 50,
    pageIndex: 1,
    queryFlowCount: true,
  };

  displayedColumns: Array<string> = [];
  dataSource: MatTableDataSource<IAccountDetailEntry>;
  resultsLength = 0;
  selection = new SelectionModel<IAccountDetailEntry>(true, []);

  range = new FormGroup({
    start: new FormControl(),
    end: new FormControl(),
  });

  @ViewChild('flexFillContainer') private flexFillContainer: ElementRef<
    HTMLElement
  >;
  @ViewChild(MatPaginator) private paginator: MatPaginator;
  private deleting = false;
  private readonly columnsToDisplay: Array<string> = [
    'select',
    'bizTime',
    'amount',
    'categoryName',
    'projectName',
    'comment',
    'operation'
  ];
  private subscription = new Subscription();

  constructor(
    private elementRef: ElementRef<HTMLElement>,
    private router: Router,
    private route: ActivatedRoute,
    private algorithm: AlgorithmService,
    private eventService: EventService,
    private communication: CommunicationService,
    private notification: NotificationService,
    private datetimeService: DatetimeService,
    private databaseService: DatabaseService,
  ) {
    this.dataSource = new MatTableDataSource();
  }

  ngOnInit(): void {
    const startDate = new Date();
    const endDate = new Date();

    startDate.setDate(1);
    this.range.setValue({
      start: startDate,
      end: endDate,
    });

    this.subscription.add(
      this.eventService
        .onViewportDimensionChange()
        .pipe(debounceTime(300))
        .subscribe((change) => {
          if (change.height) {
            this.adjustPageSize();
          }
        }),
    );

    this.displayedColumns = this.columnsToDisplay;
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }

  ngAfterViewInit(): void {
    setTimeout(() => {
      this.adjustPageSize();
    });

    this.notification.showLoading(this.elementRef.nativeElement);
    forkJoin([
      this.databaseService.getBooks(),
      this.databaseService.getShortAccounts(),
    ])
      .pipe(
        finalize(() => {
          this.notification.hideLoading();
        }),
      )
      .subscribe((datas) => {
        this.books = datas[0].data.books;

        const book = this.books[0];

        if (book) {
          this.searchKeys.bkId = book.id;
          this.onBookSelectionChange({ value: book.id } as MatSelectChange);
        }
        this.accounts = datas[1].data.accounts;
        this.initRefreshIndicator();
      });
  }

  isSummary = (index: number, rowData: IAccountDetailEntry): boolean => {
    return !rowData.id;
  };

  isNotSummary = (index: number, rowData: IAccountDetailEntry): boolean => {
    return !!rowData.id;
  };

  onBookSelectionChange(change: MatSelectChange) {
    const bookId = change.value;

    this.notification.showLoading(this.elementRef.nativeElement);
    forkJoin([
      this.databaseService.getTransactionObjects(bookId),
      this.databaseService.getBookProjects(bookId),
      this.databaseService.getMembers(bookId),
    ])
      .pipe(
        finalize(() => {
          this.notification.hideLoading();
        }),
      )
      .subscribe((datas) => {
        this.txnObjects = datas[0].data.bookTradeTargets;
        this.projects = datas[1].data.bookProjects;
        this.members = datas[2].data.bookMembers;
      });
  }

  isAllSelected(): boolean {
    const numSelected = this.selection.selected.length;
    const numRows = this.dataSource.data.length;

    return numRows > 0 && numSelected === numRows;
  }

  masterToggle() {
    if (this.isAllSelected()) {
      this.selection.clear();
    } else {
      this.dataSource.data.forEach((row) => this.selection.select(row));
    }
  }

  search(): void {
    this.communication.giveRefreshCommand();
  }

  reset(): void {
    const searchKeys = this.searchKeys;
    const startDate = new Date();
    const endDate = new Date();

    startDate.setDate(1);
    this.range.setValue({
      start: startDate,
      end: endDate,
    });

    searchKeys.bkId = this.books[0].id;
    searchKeys.amountStart = null;
    searchKeys.amountEnd = null;
    searchKeys.comment = null;
    searchKeys.recTypeList = null;
    searchKeys.mainTypeIdList = null;
    searchKeys.subTypeIdList = null;
    searchKeys.accountIdList = null;
    searchKeys.projectIdList = null;
    searchKeys.tradetgtIdList = null;
    searchKeys.memberIdList = null;
    searchKeys.reimburseList = null;
    searchKeys.pageIndex = 1;

    this.communication.giveRefreshCommand();
  }

  addNewOne(): void {
    this.router.navigate(
      [
        {
          outlets: {
            secondary: ['entry', 'add', 'new'],
          },
        },
      ],
      {
        relativeTo: this.route.parent,
      },
    );
  }

  edit(entry: IAccountDetailEntry): void {
    this.router.navigate(
      [
        {
          outlets: {
            secondary: ['entry', entry.bkId, entry.id],
          },
        },
      ],
      {
        relativeTo: this.route.parent,
      },
    );
  }

  delete(): void {
    const ids = this.selection.selected.map((item) => item.id);

    if (!ids.length || this.deleting) {
      return;
    }
    this.deleting = true;
    this.notification.showLoading(this.elementRef.nativeElement);
    this.databaseService
      .deleteEntries(ids)
      .pipe(
        map((data) => {
          if (data.error) {
            this.notification.showError(data.error);
          }
          return data;
        }),
        finalize(() => {
          this.deleting = false;
          this.notification.hideLoading();
          this.communication.giveRefreshCommand();
        }),
      )
      .subscribe();
  }

  private initRefreshIndicator(): void {
    this.subscription.add(
      merge(this.paginator.page, this.communication.acceptRefreshCommand())
        .pipe(
          debounceTime(500),
          startWith({}),
          switchMap(() => {
            const startDate = this.range.controls.start.value;
            const endDate = this.range.controls.end.value;

            this.notification.showLoading(this.elementRef.nativeElement);
            if (startDate && endDate) {
              this.searchKeys.pageIndex = this.paginator.pageIndex + 1;
              this.searchKeys.startTime = this.datetimeService.getStartDatetime(startDate),
              this.searchKeys.endTime = this.datetimeService.getEndDatetime(endDate)

              const params = { ...this.searchKeys };
              let prop;
  
              for (const key in params) {
                prop = params[key];
                if (Array.isArray(prop) && !prop.length) {
                  params[key] = null;
                }
              }
              return this.databaseService.queryEntries(params);
            }
            return of(null);
          }),
          map((data) => {
            if (data && data.error) {
              this.notification.showError(data.error);
            }
            if (data && data.data) {
              let entries: Array<IAccountDetailEntry> = [];

              data.data.dailyItems.forEach((item) => {
                entries.push({
                  bizTime: new Date(item.date).toISOString(),
                  comment: ' + ' + item.income + '   |   - ' + item.outgo,
                } as IAccountDetailEntry);
                entries = entries.concat(item.flowList);
              });

              this.resultsLength = data.data.flowCount;
              return entries;
            }
          }),
          catchError(() => {
            return of([]);
          }),
          finalize(() => {
            this.notification.hideLoading();
          }),
        )
        .subscribe((data) => {
          this.dataSource.data = data;
          this.selection.clear();
          this.notification.hideLoading();
        }),
    );
  }

  private adjustPageSize(): void {
    let pageSize = Math.floor(
      (this.flexFillContainer.nativeElement.offsetHeight - 56) / 48,
    );

    pageSize = Math.max(10, pageSize);
    this.searchKeys.pageSize = pageSize;
    this.paginator._changePageSize(pageSize);
  }
}
