import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';

import { ICategoryStatisticsResponse, IRevenueNExpenditureStatisticsResponse } from '../interface/http-response-types';
import { RequestService } from './request.service';

@Injectable()
export class StatisticsService {

  constructor(private requestService: RequestService) {}

  /**
   * @param bookId 
   * @param startDate 
   * @param endDate 
   * @param statNo 1 meaning main categories, 2 meaning subcategories, 6 revenue
   */
  getCategoryStatistics(bookId: number, startDate: Date, endDate: Date, statNo: number = 1): Observable<ICategoryStatisticsResponse> {
    return this.requestService.post('activity/bkk-frontier/api/v2/report/chartStat', {
      bkId: bookId,
      startTime: startDate.getTime(),
      endTime: endDate.getTime(),
      statNo: statNo
    });
  }

  getRevenueNExpenditureStatistics(bookId: number, startDate: Date, endDate: Date, statNo: number = 11):
    Observable<IRevenueNExpenditureStatisticsResponse> {
    return this.requestService.post('activity/bkk-frontier/api/v2/report/monthStat', {
      bkId: bookId,
      startTime: startDate.getTime(),
      endTime: endDate.getTime(),
      statNo: statNo
    });
  }
}
