import {
  Component,
  ElementRef,
  OnDestroy,
  OnInit,
  ViewChild,
} from '@angular/core';
import { FormControl, FormGroup } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { SelectionModel } from '@angular/cdk/collections';
import { MatPaginator } from '@angular/material/paginator';
import { MatSlideToggleChange } from '@angular/material/slide-toggle';
import { MatTableDataSource } from '@angular/material/table';
import { merge, of, Subscription } from 'rxjs';
import {
  catchError,
  debounceTime,
  finalize,
  map,
  startWith,
  switchMap,
} from 'rxjs/operators';

import { ENTRY_TYPES } from '../types';
import { IAccountDetailEntry } from '../interface/account-entry';
import { AlgorithmService } from 'app/shared/services/algorithm.service';
import { EventService } from 'app/shared/services/event.service';
import { CommunicationService } from 'app/shared/services/communication.service';
import { NotificationService } from 'app/shared/services/notification.service';
import { DatetimeService } from '../services/datetime.service';
import { DatabaseService } from '../services/database.service';

@Component({
  selector: 'app-account-entries',
  templateUrl: './account-entries.component.html',
  styleUrls: ['./account-entries.component.scss'],
  host: {
    class: 'd-flex flex-column flex-nowrap w-100 h-100',
  },
})
export class AccountEntriesComponent implements OnInit, OnDestroy {
  displayedColumns: Array<string> = [];
  selection = new SelectionModel<IAccountDetailEntry>(true, []);

  dataSource: MatTableDataSource<IAccountDetailEntry>;
  pageSize = 20;
  showBalance = false;

  range = new FormGroup({
    start: new FormControl(),
    end: new FormControl(),
  });

  @ViewChild('flexFillContainer') private flexFillContainer: ElementRef<
    HTMLElement
  >;
  @ViewChild(MatPaginator) private paginator: MatPaginator;
  private accountId: string;
  private deleting = false;
  private readonly columnsToDisplay: Array<string> = [
    'select',
    'bizTime',
    'amount',
    'accountBalance',
    'categoryName',
    'projectName',
    'comment',
    'operation'
  ];
  private subscription = new Subscription();

  constructor(
    private elementRef: ElementRef<HTMLElement>,
    private router: Router,
    private route: ActivatedRoute,
    private algorithm: AlgorithmService,
    private eventService: EventService,
    private notification: NotificationService,
    private communication: CommunicationService,
    private datetimeService: DatetimeService,
    private databaseService: DatabaseService,
  ) {
    this.dataSource = new MatTableDataSource();
  }

  ngOnInit(): void {
    const startDate = new Date();
    const endDate = new Date();

    startDate.setDate(1);
    this.range.setValue({
      start: startDate,
      end: endDate,
    });

    this.subscription.add(
      this.route.paramMap.subscribe((paramMap) => {
        this.accountId = paramMap.get('accountId');
      }),
    );
    this.subscription.add(
      this.eventService
        .onViewportDimensionChange()
        .pipe(debounceTime(300))
        .subscribe((change) => {
          if (change.height) {
            this.adjustPageSize();
          }
        }),
    );

    this.displayedColumns = this.columnsToDisplay.filter((item) => {
      return item !== 'accountBalance' || this.showBalance;
    });
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }

  ngAfterViewInit(): void {
    this.dataSource.paginator = this.paginator;

    setTimeout(() => {
      this.adjustPageSize();

      this.subscription.add(
        merge(
          this.range.valueChanges,
          this.communication.acceptRefreshCommand(),
        )
          .pipe(
            debounceTime(500),
            startWith({}),
            switchMap(() => {
              const startDate = this.range.controls.start.value;
              const endDate = this.range.controls.end.value;

              this.notification.showLoading(this.elementRef.nativeElement);
              if (startDate && endDate) {
                return this.databaseService.getEntries(
                  this.accountId,
                  new Date(this.datetimeService.getStartDatetime(startDate)),
                  new Date(this.datetimeService.getEndDatetime(endDate))
                );
              }
              return of(null);
            }),
            map((data) => {
              if (data) {
                const currentAccountId = this.accountId;
                const entries = data.data.flows;
                let balance: number = 0;
                const processBalance = (entry: IAccountDetailEntry) => {
                  switch (entry.recType) {
                    case ENTRY_TYPES.PAY: // pay
                      balance -= entry.amount;
                      break;
                    case ENTRY_TYPES.REVENUE: // income
                      balance += entry.amount;
                      break;
                    case ENTRY_TYPES.TRANSFER: // transfer
                      if (entry.targetId === currentAccountId) {
                        balance += entry.amount;
                      } else {
                        balance -= entry.amount;
                      }
                      break;
                    case ENTRY_TYPES.BORROW: // borrow
                      balance += entry.amount;
                    case ENTRY_TYPES.RETURN: // return
                      balance -= entry.amount;
                      break;
                    default:
                      // change balance
                      balance = entry.amount;
                      if (entry.recType !== null) {
                        console.log(entry);
                      }
                  }
                  entry.accountBalance = balance / 100;
                };

                if (this.showBalance) {
                  this.algorithm.reverseDeviceOfDuff(entries, processBalance);
                }
                return entries;
              }
            }),
            catchError(() => {
              return of([]);
            }),
            finalize(() => {
              this.notification.hideLoading();
            }),
          )
          .subscribe((data) => {
            this.dataSource.data = data || this.dataSource.data;
            this.selection.clear();
            this.notification.hideLoading();
          }),
      );
    });
  }

  isAllSelected(): boolean {
    const numSelected = this.selection.selected.length;
    const numRows = this.dataSource.data.length;

    return numRows > 0 && numSelected === numRows;
  }

  masterToggle() {
    if (this.isAllSelected()) {
      this.selection.clear();
    } else {
      this.dataSource.data.forEach((row) => this.selection.select(row));
    }
  }

  onShowBalanceChange(change: MatSlideToggleChange): void {
    if (change.checked) {
      this.range.setValue({
        start: this.datetimeService.getMinDate(),
        end: this.datetimeService.getMaxDate(),
      });
    }

    this.displayedColumns = this.columnsToDisplay.filter((item) => {
      return item !== 'accountBalance' || this.showBalance;
    });
  }

  addNewOne(): void {
    this.router.navigate(
      [
        {
          outlets: {
            secondary: ['entry', 'add', this.accountId],
          },
        },
      ],
      {
        relativeTo: this.route.parent,
      },
    );
  }

  edit(entry: IAccountDetailEntry): void {
    this.router.navigate(
      [
        {
          outlets: {
            secondary: ['entry', entry.bkId, entry.id],
          },
        },
      ],
      {
        relativeTo: this.route.parent,
      },
    );
  }

  delete(): void {
    const ids = this.selection.selected.map((item) => item.id);

    if (!ids.length || this.deleting) {
      return;
    }
    this.deleting = true;
    this.notification.showLoading(this.elementRef.nativeElement);
    this.databaseService
      .deleteEntries(ids)
      .pipe(
        map((data) => {
          if (data.error) {
            this.notification.showError(data.error);
          }
          return data;
        }),
        finalize(() => {
          this.deleting = false;
          this.notification.hideLoading();
          this.communication.giveRefreshCommand();
        }),
      )
      .subscribe();
  }

  private adjustPageSize(): void {
    const pageSize = Math.floor(
      (this.flexFillContainer.nativeElement.offsetHeight - 56) / 48,
    );

    this.pageSize = Math.max(10, pageSize);
    this.paginator._changePageSize(this.pageSize);
  }
}
