import { AfterViewInit, Component, ElementRef, OnDestroy, OnInit } from '@angular/core';
import { FormControl, FormGroup } from '@angular/forms';
import { MatSelectChange } from '@angular/material/select';
import { forkJoin, Observable, of, Subscription } from 'rxjs';
import { catchError, debounceTime, finalize, map, startWith, switchMap } from 'rxjs/operators';

import { ISunburstData } from 'app/shared/chart/chart-data';
import { CommunicationService } from 'app/shared/services/communication.service';
import { NotificationService } from 'app/shared/services/notification.service';
import { ENTRY_CATEGOTY_TYPES } from '../types';
import { IBook } from '../interface/book';
import { ICategoryStatisticsResponse, IRevenueNExpenditureStatisticsResponse } from '../interface/http-response-types';
import { DatabaseService } from '../services/database.service';
import { StatisticsService } from '../services/statistics.service';
import { DatetimeService } from '../services/datetime.service';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss'],
  host: {
    class: 'd-flex flex-column flex-nowrap w-100 h-100',
  },
})
export class DashboardComponent implements OnInit, OnDestroy, AfterViewInit {
  range = new FormGroup({
    start: new FormControl(),
    end: new FormControl(),
  });

  books: Array<IBook> = [];
  selectedBook: number;
  payCategoriesData: ISunburstData[];
  revenueCategoriesData: ISunburstData[];
  revNExpndData: Array<Array<number | Date>>;

  private subscription = new Subscription();

  constructor(
    private elementRef: ElementRef<HTMLElement>,
    private notification: NotificationService,
    private communication: CommunicationService,
    private datetimeService: DatetimeService,
    private database: DatabaseService,
    private statistics: StatisticsService
  ) {}

  ngOnInit(): void {
    const startDate = new Date();
    const endDate = new Date();

    startDate.setDate(1);
    this.range.setValue({
      start: startDate,
      end: endDate,
    });
    this.range.valueChanges.subscribe(() => {
      this.communication.giveRefreshCommand();
    });
  }

  ngAfterViewInit(): void {
    setTimeout(() => {
      this.database.getBooks().subscribe((bookData) => {
        this.books = bookData.data.books;
  
        const book = this.books[0];
  
        this.selectedBook = book.id;
        this.initRefreshIndicator();
      });
    })
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }

  onBookSelectionChange(change: MatSelectChange) {
    this.communication.giveRefreshCommand();
  }

  private initRefreshIndicator(): void {
    this.subscription.add(
      this.communication.acceptRefreshCommand()
        .pipe(
          debounceTime(500),
          startWith({}),
          switchMap(() => {
            let startDate = this.range.controls.start.value;
            let endDate = this.range.controls.end.value;

            this.notification.showLoading(this.elementRef.nativeElement);
            if (startDate && endDate) {
              startDate = new Date(this.datetimeService.getStartDatetime(startDate));
              endDate = new Date(this.datetimeService.getEndDatetime(endDate));

              return forkJoin(
                [
                  this.assemblePayCategoriesStatistics(startDate, endDate),
                  this.assembleRevenueCategoriesStatistics(startDate, endDate),
                  this.assembleRevenueNExpenditureStatistics(startDate, endDate)
                ]
              );
            }
            return of(null);
          }),
          finalize(() => {
            this.notification.hideLoading();
          })
        )
        .subscribe(() => {
          this.notification.hideLoading();
        })
    );
  }

  private assemblePayCategoriesStatistics(startDate: Date, endDate: Date): Observable<void> {
    return forkJoin(
      [
        this.database.getEntryCategories(
          this.selectedBook,
          ENTRY_CATEGOTY_TYPES.PAY
        ),
        this.statistics.getCategoryStatistics(
          this.selectedBook,
          startDate,
          endDate,
          1
        ),
        this.statistics.getCategoryStatistics(
          this.selectedBook,
          startDate,
          endDate,
          2
        )
      ]
    ).pipe(
      catchError(() => {
        return of([]);
      }),
      map((responseDatas) => {
        let hasError = false;

        if (hasError) {
          return;
        }
        responseDatas.forEach((responseData) => {
          if (responseData.error) {
            hasError = true;
            this.notification.showError(responseData.error);
          }
        });

        const categories = responseDatas[0].data.bookCategories;
        const level1Data = responseDatas[1].data;
        const level2Data = responseDatas[2].data.groups;

        this.payCategoriesData = [{
          id: '_',
          name: level1Data.title,
          value: level1Data.totalAmount / 100,
          children: level1Data.groups.map((level1Item) => {
            const categoryId = level1Item.id;
            const subCategories = categories.find((category) => {
              return category.categoryId === categoryId;
            })?.outgoSubTypes;
            const children = level2Data.filter((level2Item) => {
              return subCategories.some((category) => {
                return category.categoryId === level2Item.id;
              })
            }).map((level2Item) => {
              return {
                id: level2Item.id,
                name: level2Item.name,
                value: level2Item.amount / 100,
              };
            });

            return {
              id: level1Item.id,
              name: level1Item.name,
              value: level1Item.amount / 100,
              children: children
            };
          })
        }];
        return null;
      })
    );
  }

  private assembleRevenueCategoriesStatistics(startDate: Date, endDate: Date): Observable<void> {
    return this.statistics.getCategoryStatistics(
      this.selectedBook,
      startDate,
      endDate,
      6
    ).pipe(
      catchError(() => {
        return of({} as ICategoryStatisticsResponse);
      }),
      map((responseData) => {
        if (responseData.error) {
          this.notification.showError(responseData.error);
        }
        const level1Data = responseData.data;

        if (!level1Data) {
          return;
        }
        this.revenueCategoriesData = [{
          id: '_',
          name: level1Data.title,
          value: level1Data.totalAmount / 100,
          children: level1Data.groups.map((level1Item) => {
            return {
              id: level1Item.id,
              name: level1Item.name,
              value: level1Item.amount / 100
            };
          })
        }];
        return null;
      })
    );
  }

  private assembleRevenueNExpenditureStatistics(startDate: Date, endDate: Date): Observable<void> {
    return this.statistics.getRevenueNExpenditureStatistics(
      this.selectedBook,
      startDate,
      endDate,
      11
    ).pipe(
      catchError(() => {
        return of({} as IRevenueNExpenditureStatisticsResponse);
      }),
      map((responseData) => {
        if (responseData.error) {
          this.notification.showError(responseData.error);
        }
        const data = responseData.data;

        if (!data) {
          return;
        }
        this.revNExpndData = data.groups.map((item) => {
          return [
            new Date(item.startTime),
            item.balanceMoney,
            item.outgoMoney
          ];
        });
        return null;
      })
    );
  }
}
