import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';

import { DashboardComponent } from './dashboard/dashboard.component';
import { AccountsComponent } from './accounts/accounts.component';
import { SearchEntriesComponent } from './search-entries/search-entries.component';
import { AccountEntriesComponent } from './account-entries/account-entries.component';
import { AddOrEditEntryComponent } from './add-or-edit-entry/add-or-edit-entry.component';



const routes: Routes = [{
  path: 'dashboard',
  component: DashboardComponent
}, {
  path: 'accounts',
  component: AccountsComponent
}, {
  path: 'search',
  component: SearchEntriesComponent
}, {
  path: 'accounts/:accountId',
  component: AccountEntriesComponent
}, {
  path: 'entry/add/:accountId',
  outlet: 'secondary',
  component: AddOrEditEntryComponent
}, {
  path: 'entry/:bookId/:entryId',
  outlet: 'secondary',
  component: AddOrEditEntryComponent
}];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})

export class WacaiRoutingModule {

}