import {
  AfterViewInit,
  Component,
  ElementRef,
  OnDestroy,
  OnInit,
  QueryList,
  ViewChild,
  ViewChildren,
} from '@angular/core';
import { NgForm } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { MatSelect } from '@angular/material/select';
import { MatTabChangeEvent } from '@angular/material/tabs';
import { forkJoin, Observable, of, Subscription } from 'rxjs';
import { catchError, finalize, map } from 'rxjs/operators';

import {
  IAccountMember,
  IBaseAccountData,
  IPayCategory,
  IRevenueCategory,
  ITransactionObject,
} from '../interface/account-entry';
import { IBookMember, IBookProject } from '../interface/book';
import { AccountEntry } from './account-entry';
import { ENTRY_CATEGOTY_TYPES, ENTRY_LOAN_TYPES, ENTRY_TYPES } from '../types';
import { CommunicationService } from 'app/shared/services/communication.service';
import { NotificationService } from 'app/shared/services/notification.service';
import { CodeGeneratorService } from '../services/code-generator.service';
import { DatabaseService } from '../services/database.service';
import { IBookProjectListResponse, IMemberListResponse, ICategoryListResponse, IPayTransactionObjectListResponse, IShortAccountsResponse } from '../interface/http-response-types';


@Component({
  selector: 'app-add-or-edit-entry',
  templateUrl: './add-or-edit-entry.component.html',
  styleUrls: ['./add-or-edit-entry.component.scss'],
  host: {
    class: 'd-flex flex-column flex-nowrap w-100 h-100',
  },
})
export class AddOrEditEntryComponent implements OnInit, AfterViewInit, OnDestroy {
  accounts: Array<IBaseAccountData> = [];
  projects: Array<IBookProject> = [];
  members: Array<IBookMember> = [];
  payCategories: Array<IPayCategory> = [];
  revenueCategories: Array<IRevenueCategory> = [];
  txnObjects: Array<ITransactionObject> = [];
  creditors: Array<IBaseAccountData> = [];
  loanTypes = [
    ENTRY_LOAN_TYPES.BORROW,
    ENTRY_LOAN_TYPES.LEND,
    ENTRY_LOAN_TYPES.RECEIVE,
    ENTRY_LOAN_TYPES.REPAYMENT,
  ];

  entry: AccountEntry;
  selectedMembers: Array<IBookMember>;
  bizDatetime: Date = new Date();

  selectedTabIndex = 0;
  saving = false;

  private bookId: number | string;
  private accountId: string;
  private isNew = false;
  @ViewChild(NgForm) private entryForm: NgForm;
  @ViewChildren(MatSelect) private selects: QueryList<MatSelect>;
  private getEntrySsp: Subscription;
  private subscription = new Subscription();

  constructor(
    private elementRef: ElementRef<HTMLElement>,
    private router: Router,
    private route: ActivatedRoute,
    private generator: CodeGeneratorService,
    private communication: CommunicationService,
    private notification: NotificationService,
    private databaseService: DatabaseService,
  ) {
    this.entry = new AccountEntry();
    this.entry.bizId = this.generator.generateBIZID();
    this.entry.recType = ENTRY_TYPES.PAY;
  }

  ngOnInit(): void {
    this.subscription.add(
      this.route.paramMap.subscribe((paramMap) => {
        const entryId = paramMap.get('entryId');
        const accountId = paramMap.get('accountId');

        if (accountId) {
          this.accountId = accountId === 'new' ? undefined : accountId;
          this.isNew = true;
        } else if (entryId) {
          this.isNew = false;
        }
      })
    );
  }

  ngAfterViewInit(): void {
    setTimeout(() => {
      this.notification.showLoading(this.elementRef.nativeElement);
      this.databaseService.getBooks().subscribe((booksData) => {
        if (booksData && booksData.data && booksData.data.books[0]) {
          const book = booksData.data.books[0];

          this.bookId = book.id || book.uuid;
          this.entry.bkId = this.bookId as number;
          this.entry.bookId = book.uuid;
          forkJoin([
            this.databaseService.getTransactionObjects(this.bookId),
            this.databaseService.getShortAccounts(),
            this.databaseService.getBookProjects(this.bookId),
            this.databaseService.getMembers(this.bookId),
            this.databaseService.getEntryCategories(this.bookId, ENTRY_CATEGOTY_TYPES.PAY),
            this.databaseService.getEntryCategories(this.bookId, ENTRY_CATEGOTY_TYPES.REVENUE),
            this.databaseService.getShortAccounts(-1),
          ])
            .pipe(
              finalize(() => {
                this.notification.hideLoading();
              }),
            )
            .subscribe((datas: [
              IPayTransactionObjectListResponse,
              IShortAccountsResponse,
              IBookProjectListResponse,
              IMemberListResponse,
              ICategoryListResponse,
              ICategoryListResponse,
              IShortAccountsResponse
            ]) => {
              this.txnObjects = datas[0].data.bookTradeTargets;
              this.accounts = datas[1].data.accounts;
              this.projects = datas[2].data.bookProjects;
              this.members = datas[3].data.bookMembers;
              this.payCategories = datas[4].data.bookCategories;
              this.revenueCategories = datas[5].data.bookCategories;
              this.creditors = datas[6].data.accounts;

              if (this.isNew) {
                if (!this.entry.accountId && this.accounts[0]) {
                  this.entry.accountId = this.accounts[0].uuid;
                }
                this.entry.projectId = this.projects[1].uuid;
                this.selectedMembers = this.members.slice(0, 1);
              } else {
                const entryId = this.route.snapshot.paramMap.get('entryId');
                const bookId = this.route.snapshot.paramMap.get('bookId');

                this.getCurrentEntry(bookId, entryId);
              }
            });
          this.onSelectedTabChange({
            index: 0
          } as MatTabChangeEvent);
        }
      });
    }, 500);
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }

  onSelectedTabChange(change: MatTabChangeEvent): void {
    const entry = this.entry;
    const recType = change.index + 1;
    let categroy: ENTRY_CATEGOTY_TYPES;

    entry.recType = recType;

    switch (recType) {
      case ENTRY_TYPES.PAY:
        categroy = ENTRY_CATEGOTY_TYPES.PAY;
      case ENTRY_TYPES.REVENUE:
        if (typeof categroy === 'undefined') {
          categroy = ENTRY_CATEGOTY_TYPES.REVENUE;
        }

        if (!entry.accountId && this.accountId) {
          entry.accountId = this.accountId;
          break;
        }

        const firstCategory = this.payCategories[0];

        this.checkValuesWhetherExisted();
        if (!entry.categoryId && firstCategory) {
          if (
            firstCategory.outgoSubTypes &&
            firstCategory.outgoSubTypes[0]
          ) {
            entry.categoryId = firstCategory.outgoSubTypes[0].categoryId;
          } else {
            entry.categoryId = firstCategory.categoryId;
          }
        }
        break;
      case ENTRY_TYPES.TRANSFER:
        this.checkValuesWhetherExisted();

        if (!entry.accountId && this.accountId) {
          entry.accountId = this.accountId;
        }
        if (!entry.targetId && this.accounts[0]) {
          entry.targetId = this.accounts[0].uuid;
        }
        break;
      default:
        this.checkValuesWhetherExisted();

        entry.lendType = 1;
        if (!entry.targetId) {
          entry.targetId = this.accountId || (this.accounts[0] ? this.accounts[0].uuid : undefined);
        }
        if (!entry.accountId) {
          entry.accountId = (this.creditors && this.creditors[0]) ? this.creditors[0].uuid : undefined;
        }
        break;
    }
  }

  save(): void {
    this.update().subscribe((result) => {
      if (result) {
        this.cancel();
      }
    });
  }

  saveAndNew(): void {
    const controls = this.entryForm.controls;

    this.entryForm.form.updateValueAndValidity();
    for (const key in controls) {
      controls[key].markAsTouched();
    }
    this.update().subscribe((result) => {
      if (result) {
        this.entry.id = 0;
        this.entry.bizId = this.generator.generateBIZID();
      }
    });
  }

  cancel(): void {
    this.router.navigate(
      [
        {
          outlets: {
            secondary: null,
          },
        },
      ],
      {
        relativeTo: this.route.parent,
      },
    );
  }

  private update(): Observable<boolean> {
    this.checkValuesWhetherExisted();

    if (this.entryForm && this.entryForm.valid) {
      const entry = this.entry;

      // this.accounts.some((item) => {
      //   if (item.uuid === entry.accountId) {
      //     entry.account = {
      //       key: item.uuid,
      //       label: item.name
      //     };
      //     return true;
      //   }
      //   return false;
      // });
      // this.payCategories.some((item) => {
      //   if (item.categoryId === entry.categoryId) {
      //     entry.category = {
      //       key: item.categoryId,
      //       label: item.name
      //     };
      //     return true;
      //   }
      //   return false;
      // });
      // this.members.some((item) => {
      //   if (item.uuid === this.member.uuid) {
      //     entry.member = {
      //       key: item.uuid,
      //       label: item.name
      //     };
      //     return true;
      //   }
      //   return false;
      // });
      // this.projects.some((item) => {
      //   if (item.uuid === entry.projectId) {
      //     entry.project = {
      //       key: item.uuid,
      //       label: item.name
      //     };
      //     entry.projectName = item.name;
      //     return true;
      //   }
      //   return false;
      // });
      // this.txnObjects.some((item) => {
      //   if (item.uuid === entry.tradetgtId) {
      //     entry.tradetgt = {
      //       key: item.uuid,
      //       label: item.name
      //     };
      //     entry.tradetgtName = item.name;
      //     return true;
      //   }
      //   return false;
      // });
      switch (entry.recType) {
        case ENTRY_TYPES.PAY:
        case ENTRY_TYPES.REVENUE:
          entry.targetId = undefined;
          entry.profit = undefined;
          entry.lendType = undefined;
          entry.recSubtype = undefined;
          entry.members = this.selectedMembers.map((item) => {
            return {
              memberId: item.uuid,
              amount: entry.amount,
            };
          });
          break;
        case ENTRY_TYPES.TRANSFER:
          if (entry.accountId === entry.targetId) {
            return;
          }
          entry.categoryId = undefined;
          entry.projectId = undefined;
          entry.tradetgtId = undefined;
          entry.profit = undefined;
          entry.lendType = undefined;
          entry.recSubtype = undefined;
          entry.reimburse = 0;
          entry.members = this.members.slice(0, 1).map((item) => {
            return {
              memberId: item.uuid,
              amount: entry.amount,
            };
          });
          break;
        default:
          entry.categoryId = undefined;
          entry.projectId = undefined;
          entry.tradetgtId = undefined;
          entry.profit = 0;
          entry.reimburse = 0;
          entry.targetAmount = entry.amount;
          switch (entry.lendType) {
            case ENTRY_LOAN_TYPES.LEND:
            case ENTRY_LOAN_TYPES.REPAYMENT:
              entry.recSubtype = 1;
              break;
            default:
              entry.recSubtype = 0;
          }
          if (
            entry.lendType === ENTRY_LOAN_TYPES.RECEIVE ||
            entry.lendType === ENTRY_LOAN_TYPES.REPAYMENT
          ) {
            entry.recType = ENTRY_TYPES.RETURN;
          }
          entry.members = [
            {
              amount: entry.amount,
            } as IAccountMember,
          ];
          break;
      }
      entry.bizTime = this.bizDatetime.toISOString();
      if (typeof entry.comment === 'undefined') {
        entry.comment = '';
      }

      this.saving = true;
      this.notification.showLoading(this.elementRef.nativeElement);

      return this.databaseService.saveEntry([entry]).pipe(
        catchError(() => of(false)),
        map((data) => {
          if (typeof data !== 'boolean' && data.error) {
            this.notification.showError(data.error);
            return false;
          }
          return true;
        }),
        finalize(() => {
          this.saving = false;
          this.notification.hideLoading();
          this.communication.giveRefreshCommand();
        }),
      );
    }
    return of(false);
  }

  private checkValuesWhetherExisted(): void {
    this.selects.forEach((item) => {
      if (item.multiple) {
        if (item.value) {
          const values = item.value.filter((value) => {
            return item.options.some(option => option.value === value);
          });

          item.ngControl.control.setValue(values);
        }
      } else {
        if (!item.options.some(option => option.value === item.value)) {
          item.ngControl.control.setValue(null);
        }
      }
    });
  }

  private getCurrentEntry(bookId: string, entryId: string): void {
    if (this.getEntrySsp) {
      this.getEntrySsp.unsubscribe();
    }
    this.notification.showLoading(this.elementRef.nativeElement);
    this.getEntrySsp = this.databaseService.getEntry(bookId, entryId).pipe(
      finalize(() => {
        this.getEntrySsp = undefined;
        this.notification.hideLoading();
      })
    ).subscribe((data) => {
      if (data.error) {
        this.notification.showError(data.error);
        return;
      }
      const entry = data.data as unknown as AccountEntry;

      entry.amount = entry.amount / 100;
      this.accountId = entry.accountId;
      this.bizDatetime = new Date(entry.bizTime);
      if (Array.isArray(entry.members)) {
        this.selectedMembers = this.members.filter((member) => {
          return entry.members.some(item => item.memberId === member.uuid);
        });
      } else {
        this.selectedMembers = this.members.slice(0, 1);
      }
      this.selectedTabIndex = (entry.recType > 5 ? 4 : entry.recType) - 1;
      this.entry = entry;
    });
  }
}
