import { Injectable } from '@angular/core';
import { Observable, of } from 'rxjs';

import { IRequestAccountEntry } from '../interface/account-entry';
import { IBook } from '../interface/book';
import {
  IAccountListResponse,
  IAccountsResponse,
  IBookResponse,
  IBookProjectListResponse,
  IHiddenAccountListResponse,
  IAccountEntriesResponse,
  ICategoryListResponse,
  IPayTransactionObjectListResponse,
  IShortAccountsResponse,
  IMemberListResponse,
  IQueryAccountEntryResponse,
  IAccountEntryResponse,
} from '../interface/http-response-types';
import { RequestService } from './request.service';

@Injectable()
export class DatabaseService {
  private books: IBook[];

  constructor(private requestService: RequestService) {}

  getBooks(): Observable<IBookResponse> {
    if (this.books) {
      return of({
        code: null,
        error: null,
        data: {
          books: this.books,
        },
      });
    }
    return this.requestService.get(
      'activity/bkk-frontier/api/v2/book/web/query',
    );
  }

  getAccountTypeList(): Observable<IAccountListResponse> {
    return this.requestService.get('setting/account_allAccountTypes.action', {
      timesamp: Date.now(),
    });
  }

  getAccountList(
    hidden: boolean = true,
    reqBalance: boolean = false,
    loanFlag: boolean = true,
  ): Observable<IAccountsResponse> {
    return this.requestService.get('setting/account_list.action', {
      timesamp: Date.now(),
      hidden,
      reqBalance,
      loanFlag,
    }) as Observable<IAccountsResponse>;
  }

  getVisibleAccountList(): Observable<IAccountListResponse> {
    return this.requestService.post('activity/bkk-frontier/api/account/index', {
      localTime: Date.now(),
      timeZoneId: this.requestService.TIME_ZONE_ID,
      useCompleteSort: true,
    });
  }

  getHiddenAccountList(): Observable<IHiddenAccountListResponse> {
    return this.requestService.post(
      'activity/bkk-frontier/api/account/hiddenList',
      {
        localTime: Date.now(),
        timeZoneId: this.requestService.TIME_ZONE_ID,
        useCompleteSort: true,
      },
    );
  }

  getShortAccounts(
    accountOption: number = 1,
  ): Observable<IShortAccountsResponse> {
    return this.requestService.get(
      'activity/bkk-frontier/api/account/web/query',
      {
        ___t: Date.now(),
        accountOption,
      },
    );
  }

  getEntryCategories(
    bookId: number | string,
    categoryType: number,
  ): Observable<ICategoryListResponse> {
    return this.requestService.get(
      'activity/bkk-frontier/api/v2/category/web/query',
      {
        ___t: Date.now(),
        bkId: bookId,
        categoryType,
      },
    );
  }

  getTransactionObjects(
    bookId: number | string,
  ): Observable<IPayTransactionObjectListResponse> {
    return this.requestService.get(
      'activity/bkk-frontier/api/v2/trade/target/web/query',
      {
        ___t: Date.now(),
        bkId: bookId,
      },
    );
  }

  getBookProjects(
    bookId: number | string,
  ): Observable<IBookProjectListResponse> {
    return this.requestService.get(
      'activity/bkk-frontier/api/v2/project/web/query',
      {
        ___t: Date.now(),
        bkId: bookId,
      },
    );
  }

  getMembers(bookId: number | string): Observable<IMemberListResponse> {
    return this.requestService.get(
      'activity/bkk-frontier/api/v2/book/member/web/query',
      {
        ___t: Date.now(),
        bkId: bookId,
      },
    );
  }

  queryEntries(params: {
    [key: string]: boolean | number | string | Array<number | string>;
  }): Observable<IQueryAccountEntryResponse> {
    return this.requestService.post(
      'activity/bkk-frontier/api/v2/flow/list/web',
      params,
    );
  }

  getEntries(
    account: string,
    startDate: Date,
    endDate: Date,
  ): Observable<IAccountEntriesResponse> {
    const params = {
      accountId: account,
      startDate: startDate.getTime(),
      endDate: endDate.getTime(),
      timeZoneId: this.requestService.TIME_ZONE_ID,
      localTime: Date.now(),
    };

    return this.requestService.post(
      'activity/bkk-frontier/api/account/detail/flow',
      params,
    );
  }

  getEntry(bookId: string, entryId: string): Observable<IAccountEntryResponse> {
    return this.requestService.get(
      'activity/bkk-frontier/api/v2/flow/query/web/' + bookId + '/' + entryId,
    );
  }

  saveEntry(
    datas: IRequestAccountEntry[],
  ): Observable<IAccountEntriesResponse> {
    return this.requestService.post('activity/bkk-frontier/api/v2/flow/save', {
      flows: datas,
    });
  }

  deleteEntries(entryIds: Array<number>): Observable<IAccountEntriesResponse> {
    return this.requestService.post(
      'activity/bkk-frontier/api/v2/flow/batch/delete',
      { flowIds: entryIds },
    );
  }
}
